const rows = $input.all().map(i => i.json);

// First result set is summary, rest are agency breakdown
const summary = rows[0] || {};
const agencyRows = rows.slice(1).filter(r => r.agency);

const wr = parseFloat(summary.win_rate_pct) || 0;
const qtdWr = parseFloat(summary.qtd_win_rate) || 0;
const trend = qtdWr > wr ? '📈' : qtdWr < wr ? '📉' : '➡️';

// Pipeline coverage ratio: won value vs total pipeline
const wonVal = parseFloat(summary.total_won_value) || 0;
const lostVal = parseFloat(summary.total_lost_value) || 0;
const totalBid = wonVal + lostVal;
const bidToWin = totalBid > 0 ? (wonVal / totalBid * 100).toFixed(1) : 'N/A';

// B:W ratio (how many bids per win)
const bidsPerWin = parseInt(summary.total_won) > 0
  ? (parseInt(summary.total_competed) / parseInt(summary.total_won)).toFixed(1)
  : 'N/A';

return [{ json: {
  summary,
  agency_breakdown: agencyRows,
  computed: {
    win_rate_pct: wr,
    qtd_win_rate: qtdWr,
    trend_icon: trend,
    bid_to_win_value_pct: bidToWin,
    bids_per_win: bidsPerWin,
    total_won_value_m: (wonVal / 1e6).toFixed(2),
    total_lost_value_m: (lostVal / 1e6).toFixed(2)
  },
  has_data: parseInt(summary.total_decisions) > 0
}}];

