const data = $('Compute Win Rates').first().json;
const claudeRaw = $input.first().json;
let insight = '';
try { insight = claudeRaw.content[0].text; } catch(e) {}

const c = data.computed;
const s = data.summary;
const agency = data.agency_breakdown;

const agencyLines = agency.slice(0,3).map(a =>
  `  ${a.agency}: ${a.won}W/${a.lost}L (${a.wr}%)`
).join('\n');

const msg = `📊 *GDA Weekly BD Digest*
_${new Date().toLocaleDateString('en-US', {month:'short', day:'numeric', year:'numeric'})}_

*FY26 Win Rate: ${c.win_rate_pct}% ${c.trend_icon}*
QTD: ${c.qtd_win_rate}% | Bids/Win: ${c.bids_per_win}
Won: $${c.total_won_value_m}M | Lost: $${c.total_lost_value_m}M
Decisions: ${s.total_won}W / ${s.total_lost}L / ${s.total_nogo} No-Go

*Top Agencies:*
${agencyLines || '  No data yet'}

*Analyst Take:*
${insight}`;

return [{ json: { message: msg, data, insight, generated_at: new Date().toISOString() } }];
